                      const value = item?.id;

                      if (!ld.isEmpty(value)) {
                        pm.expect(typeof value).to.equal("string");
                      }
                    }
                  })

                }
              }
              pm.test('item format to be uuid', function() {
                const value = ld.get(responseData, `item`, null);
                if (value !== null && value !== undefined && typeof value === 'string') {
                  pm.expect(value).to.match(/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i);
                }
              })

              {
                // Condition: Raw data type and parent property is not an array
                // pathStr: item
                // subKey: jobTitle
                // required: []
                let requiredField = true
                if (requiredField || ld.get(item, 'jobTitle')) {
                  pm.test(`'item field has jobTitle that is of type string'`, function() {
                    let parent = item;
                    if (pm.expect(parent).to.have.nested.property(`jobTitle`)) {
                      const value = item?.jobTitle;

                      pm.expect(typeof value).to.equal("string");

                    }
                  })

                }
              } {
                // Condition: Raw data type and parent property is not an array
                // pathStr: item
                // subKey: name
                // required: []
                let requiredField = true
                if (requiredField || ld.get(item, 'name')) {
                  pm.test(`'item field has name that is of type string'`, function() {
                    let parent = item;
                    if (pm.expect(parent).to.have.nested.property(`name`)) {
                      const value = item?.name;

                      pm.expect(typeof value).to.equal("string");

                    }
                  })

                }
              } {
                // Condition: Raw data type and parent property is not an array
                // pathStr: item
                // subKey: email
                // required: []
                let requiredField = true
                if (requiredField || ld.get(item, 'email')) {
                  pm.test(`'item field has email that is of type string'`, function() {
                    let parent = item;
                    if (pm.expect(parent).to.have.nested.property(`email`)) {
                      const value = item?.email;

                      pm.expect(typeof value).to.equal("string");

                    }
                  })

                }
              }
